package ru.memearena.user.application;
import org.springframework.http.HttpStatus; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional; import ru.memearena.error.*; import ru.memearena.security.TokenService; import ru.memearena.scout.application.ScoutService; import ru.memearena.session.domain.UserSession; import ru.memearena.session.infrastructure.UserSessionRepository; import ru.memearena.user.domain.UserProfile; import ru.memearena.user.infrastructure.UserProfileRepository; import java.time.*; import java.util.UUID; import java.util.regex.Pattern;
@Service public class UserProfileService { @Transactional public GuestCreationResult createGuest(String raw){String n=normalize(raw); if(repo.existsByNicknameIgnoreCase(n)) throw new ApiException(HttpStatus.CONFLICT,ErrorCode.NICKNAME_ALREADY_EXISTS,"Nickname already exists"); var now=Instant.now(clock); var user=repo.save(new UserProfile(UUID.randomUUID(),n,now)); scout.createStats(user.getId(),now); return new GuestCreationResult(user,null,null);} private static final Pattern NICK=Pattern.compile("^[\\p{IsCyrillic}A-Za-z0-9_-]{3,30}$"); private final UserProfileRepository repo; private final Clock clock; private final UserSessionRepository sessions; private final TokenService tokens; private final ScoutService scout; public UserProfileService(UserProfileRepository repo,Clock clock,UserSessionRepository sessions,TokenService tokens,ScoutService scout){this.repo=repo;this.clock=clock;this.sessions=sessions;this.tokens=tokens;this.scout=scout;} @Transactional public GuestCreationResult createGuest(String raw,String installationId,String ipHash){String n=normalize(raw); if(repo.existsByNicknameIgnoreCase(n)) throw new ApiException(HttpStatus.CONFLICT,ErrorCode.NICKNAME_ALREADY_EXISTS,"Nickname already exists"); var now=Instant.now(clock); var user=repo.save(new UserProfile(UUID.randomUUID(),n,now)); scout.createStats(user.getId(),now); String rawToken=tokens.generate(); String hash=tokens.sha256(rawToken); var expires=now.plus(Duration.ofDays(90)); sessions.save(new UserSession(UUID.randomUUID(),user.getId(),hash,now,expires,installationId,ipHash)); return new GuestCreationResult(user,rawToken,expires);} @Transactional(readOnly=true) public UserProfile get(UUID id){return repo.findById(id).orElseThrow(()->new ApiException(HttpStatus.NOT_FOUND,ErrorCode.USER_NOT_FOUND,"User not found"));} @Transactional public void logout(java.util.UUID sessionId){sessions.findById(sessionId).ifPresent(s->s.revoke(Instant.now(clock)));} public static String normalize(String raw){String n=raw==null?"":raw.trim(); if(!NICK.matcher(n).matches()) throw new ApiException(HttpStatus.BAD_REQUEST,ErrorCode.VALIDATION_ERROR,"Invalid nickname"); return n;} }
